// Script: generar_20_iconos_por_especie.js
// Que hace: corrige que el emoji de la mascota siempre mostrara un perrito
// 🐶, sin importar si era un gato, conejo, o ave. Ahora el icono
// corresponde a la especie real de cada mascota.
//
//   1) utils/iconoEspecie.ts (ARCHIVO NUEVO) -- mapeo compartido de
//      especie -> emoji (Perro 🐕, Gato 🐈, Conejo 🐇, Ave 🐦, cualquier
//      otra cosa incluyendo "Otro" -> 🐾), para reutilizar en cualquier
//      pantalla sin duplicar el mapeo.
//
//   2) components/SelectorMascota.tsx -- ahora usa la utilidad
//      compartida en vez de tener su propia copia del mapeo.
//
//   3) components/DashboardContenido.tsx -- el icono del banner de
//      saludo y el avatar grande del hero ahora muestran la especie
//      real de la mascota activa.
//
//   4) app/perfil/page.tsx -- el avatar grande del header ahora muestra
//      la especie real.
//
//   5) app/registro-diario/page.tsx -- el icono junto al banner
//      informativo de especie ahora usa el mapeo completo (antes solo
//      distinguia gato vs todo lo demas). La logica de categorias del
//      formulario por especie (gato/perro) y la lista de "zonas del
//      cuerpo" del detalle de heridas NO se tocaron, siguen igual.
//
// Como correrlo: node generar_20_iconos_por_especie.js
// Confirma "OK" para los 5 archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('utils/iconoEspecie.ts', "");
escribir('components/SelectorMascota.tsx', "");
escribir('components/DashboardContenido.tsx', "");
escribir('app/perfil/page.tsx', "");
escribir('app/registro-diario/page.tsx', "");
